---
import BaseLayout from '../../layouts/BaseLayout.astro';
import { getCollection, render } from 'astro:content';
import { formatDate } from '../../utils/format-date';

const isDev = import.meta.env.DEV;
const allPosts = await getCollection('blog', ({ data }) => isDev || !data.draft);
const posts = allPosts.sort(
  (a, b) => b.data.date.valueOf() - a.data.date.valueOf()
);

// Collect reading times at build time — no runtime JS
const readingTimes = await Promise.all(
  posts.map(async (post) => {
    const { remarkPluginFrontmatter } = await render(post);
    return (remarkPluginFrontmatter.minutesRead as string) ?? '1 min read';
  })
);
---

<BaseLayout title="Blog - AstroStatic">
  <section class="mx-auto max-w-3xl px-4 py-16">
    <h1 class="text-4xl font-bold mb-8">Blog</h1>
    <div class="space-y-8">
      {posts.map((post, i) => (
        <article class="border-b border-gray-200 dark:border-gray-800 pb-8">
          <div class="flex items-center gap-3 text-sm text-gray-500 dark:text-gray-400">
            <time datetime={post.data.date.toISOString().split('T')[0]}>
              {formatDate(post.data.date)}
            </time>
            <span aria-hidden="true">&middot;</span>
            <span>{readingTimes[i]}</span>
          </div>
          <h2 class="mt-1 text-2xl font-semibold">
            <a href={`/blog/${post.id}`} class="hover:text-blue-600 dark:hover:text-blue-400 transition-colors rounded focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 dark:focus-visible:outline-blue-400">
              {post.data.title}
            </a>
          </h2>
          <p class="mt-2 text-gray-600 dark:text-gray-400">{post.data.description}</p>
          {post.data.tags.length > 0 && (
            <div class="mt-2 flex flex-wrap gap-2">
              {post.data.tags.map((tag) => (
                <a
                  href={`/blog/tags/${encodeURIComponent(tag)}`}
                  class="inline-flex items-center rounded-full bg-gray-100 dark:bg-gray-800 px-2.5 py-0.5 text-xs font-medium text-gray-600 dark:text-gray-400 hover:bg-blue-100 dark:hover:bg-blue-900 hover:text-blue-700 dark:hover:text-blue-300 transition-colors focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-500"
                >
                  {tag}
                </a>
              ))}
            </div>
          )}
          <a href={`/blog/${post.id}`} aria-label={`Read more about ${post.data.title}`} class="mt-3 inline-block text-sm font-medium text-blue-600 dark:text-blue-400 hover:underline rounded focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 dark:focus-visible:outline-blue-400">
            Read more &rarr;
